def _extract_element_data(element):
    """
    Recursively extract data from an XML element.
    
    Args:
        element: lxml Element object
        
    Returns:
        dict or str: Extracted element data
    """
    if len(element) == 0:
        # Leaf node - return text content
        return element.text if element.text else ''
    
    # Has child elements
    result = {}
    
    # Add attributes if any
    if element.attrib:
        result['@attributes'] = dict(element.attrib)
    
    # Add text content if any
